  // ========== ToolCallLog ==========

  // LIST tool-call-logs
  router.get("/tool-call-logs", async (c) => {
    try {
      const url = new URL(c.req.url)
      const page = Math.max(1, parseInt(url.searchParams.get("page") || "1"))
      const limit = Math.min(Math.max(1, parseInt(url.searchParams.get("limit") || "20")), 100)
      const search = url.searchParams.get("search") || ""
      const orderBy = url.searchParams.get("orderBy") || "createdAt"
      const order = (url.searchParams.get("order") || "desc") as "asc" | "desc"

      let where: any = {}
      if (search) {
        where = {
          OR: [
            { chatSessionId: { contains: search, mode: "insensitive" } },
            { messageId: { contains: search, mode: "insensitive" } },
            { toolName: { contains: search, mode: "insensitive" } },
          ]
        }
      }

      // Additional query param filters
      const reserved = new Set(["page", "limit", "search", "orderBy", "order"])
      for (const [key, value] of url.searchParams.entries()) {
        if (!reserved.has(key) && value !== "") {
          if (value === "true") where[key] = true
          else if (value === "false") where[key] = false
          else where[key] = value
        }
      }

      const [items, total] = await Promise.all([
        prisma.toolCallLog.findMany({
          where,
          orderBy: { [orderBy]: order },
          skip: (page - 1) * limit,
          take: limit,
        }),
        prisma.toolCallLog.count({ where }),
      ])

      return c.json({ ok: true, data: { toolCallLogs: items, total, page, limit } })
    } catch (error: any) {
      console.error("[Admin] List ToolCallLog error:", error)
      return c.json({ error: { code: "list_failed", message: error.message } }, 500)
    }
  })

