  // ========== FeatureSession ==========

  // LIST feature-sessions
  router.get("/feature-sessions", async (c) => {
    try {
      const url = new URL(c.req.url)
      const page = Math.max(1, parseInt(url.searchParams.get("page") || "1"))
      const limit = Math.min(Math.max(1, parseInt(url.searchParams.get("limit") || "20")), 100)
      const search = url.searchParams.get("search") || ""
      const orderBy = url.searchParams.get("orderBy") || "createdAt"
      const order = (url.searchParams.get("order") || "desc") as "asc" | "desc"

      let where: any = {}
      if (search) {
        where = {
          OR: [
            { name: { contains: search, mode: "insensitive" } },
            { intent: { contains: search, mode: "insensitive" } },
            { affectedPackages: { contains: search, mode: "insensitive" } },
            { schemaName: { contains: search, mode: "insensitive" } },
            { applicablePatterns: { contains: search, mode: "insensitive" } },
            { projectId: { contains: search, mode: "insensitive" } },
          ]
        }
      }

      // Additional query param filters
      const reserved = new Set(["page", "limit", "search", "orderBy", "order"])
      for (const [key, value] of url.searchParams.entries()) {
        if (!reserved.has(key) && value !== "") {
          if (value === "true") where[key] = true
          else if (value === "false") where[key] = false
          else where[key] = value
        }
      }

      const [items, total] = await Promise.all([
        prisma.featureSession.findMany({
          where,
          orderBy: { [orderBy]: order },
          skip: (page - 1) * limit,
          take: limit,
          include: {
            _count: { select: { requirements: true, designDecisions: true, classificationDecisions: true, analysisFindings: true, integrationPoints: true, testCases: true, implementationTasks: true, implementationRuns: true } },
          },
        }),
        prisma.featureSession.count({ where }),
      ])

      return c.json({ ok: true, data: { featureSessions: items, total, page, limit } })
    } catch (error: any) {
      console.error("[Admin] List FeatureSession error:", error)
      return c.json({ error: { code: "list_failed", message: error.message } }, 500)
    }
  })

